#!/usr/bin/env python3
"""
deploy_v19_34_222b.py - finish v222: commit the ma_stack revert (C) with a
self-contained test. The first v222 run reverted technical_quality.py + removed
junk files but FAILED at pytest (it referenced a prior-job test that was never
pushed to this repo), so the revert is sitting UNCOMMITTED. This commits it.

Idempotent + checksum-guarded. B (L2 slots) remains shipped & unchanged.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_222b.py
  python3 /tmp/deploy_v19_34_222b.py
"""
import os, base64, hashlib, shutil, subprocess, sys, py_compile

REPO=os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO): REPO=os.getcwd()
SVC=os.path.join(REPO,"backend","services","tqs","technical_quality.py")
TEST=os.path.join(REPO,"backend","tests","test_v19_34_222_ma_stack_trend.py")
STALE=os.path.join(REPO,"backend","tests","test_v19_34_221_ma_stack_alignment.py")

MARKER="v19.34.222"
V221_SHA="2dea8604e58e293d250eed43256e46f6a8137f98fe678c7193e68334753f0811"
NEW_SHA="f0f529f3cab3421665c0828a4f9c34ed801befebfe3c3b30f5c42df0ef5e3e72"
B64=""
TEST_B64=""


def fail(m):
    print("\n[FAIL] "+m); sys.exit(1)


def main():
    print("== deploy_v19_34_222b ==\nrepo: "+REPO)
    cur=open(SVC,"rb").read(); cur_sha=hashlib.sha256(cur).hexdigest()
    new_bytes=base64.b64decode(B64)
    assert hashlib.sha256(new_bytes).hexdigest()==NEW_SHA, "payload corrupt"
    if MARKER in cur.decode("utf-8","ignore"):
        print("[ok] technical_quality.py already reverted (v222 marker).")
    elif cur_sha==V221_SHA:
        shutil.copy2(SVC,SVC+".v222b.bak"); open(SVC,"wb").write(new_bytes)
        try:
            py_compile.compile(SVC,doraise=True)
        except py_compile.PyCompileError as e:
            shutil.copy2(SVC+".v222b.bak",SVC); fail("py_compile failed, rolled back: "+str(e))
        os.remove(SVC+".v222b.bak"); print("[ok] technical_quality.py reverted + compiles.")
    else:
        fail("technical_quality.py drift (sha="+cur_sha[:12]+") - aborting.")

    os.makedirs(os.path.dirname(TEST),exist_ok=True)
    open(TEST,"wb").write(base64.b64decode(TEST_B64)); print("[ok] wrote self-contained test")
    for jf in (STALE, os.path.join(REPO,"="), os.path.join(REPO,"main")):
        if os.path.exists(jf):
            subprocess.run(["git","rm","-f","--quiet",jf],cwd=REPO)
            if os.path.exists(jf): os.remove(jf)
            print("[ok] removed "+os.path.relpath(jf,REPO))

    print("\n== pytest ==")
    r=subprocess.run([sys.executable,"-m","pytest",TEST,"-q"],cwd=os.path.join(REPO,"backend"))
    if r.returncode!=0: fail("pytest failed - NOT committing.")
    print("[ok] tests green.")

    print("\n== git commit + push ==")
    subprocess.run(["git","add","-A"],cwd=REPO)
    cm=subprocess.run(["git","commit","-m",
        "v19.34.222 revert v221 ma_stack EMA-alignment (intraday/daily timeframe "
        "mix); restore v215 trend logic; self-contained test; drop junk files"],cwd=REPO)
    if cm.returncode==0:
        subprocess.run(["git","push"],cwd=REPO); print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit - working tree already clean/committed.")
    print("\n[DONE] No restart needed (already running the reverted code).")
    print("B (L2 slots) status:  curl -s localhost:8001/api/ib/l2-router-status | python3 -m json.tool")


if __name__=="__main__":
    main()
